class Main {
  public static void main(String[] args) {
    int temperature = 30;

    if (temperature > 80) {
      System.out.println("It's hot! 🥵");
    } else if (temperature > 60) {
      System.out.println("It's warm. 😎");
    } else if (temperature > 40) {
      System.out.println("It's cool. 🥶");
    } else {
      System.out.println("It's freezing! ⛄");
    }
  }
}
